changeSet.sql:
            CREATE OR REPLACE FUNCTION check_car_price() RETURNS TRIGGER AS $$
            BEGIN
                IF NEW.price < 0 THEN RAISE EXCEPTION 'Price cannot be negative'; END IF;
            RETURN NEW;
            END; $$ LANGUAGE plpgsql;

            CREATE TRIGGER trg_check_price BEFORE INSERT OR UPDATE ON cars
                                                                FOR EACH ROW EXECUTE FUNCTION check_car_price();
